package main

import (
	"bytes"
	"fmt"
	"html"
	"mime"
	"mime/quotedprintable"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with both plain text and HTML bodies containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject to remove newlines and prevent header injection
	sanitizedHeaderSubject := strings.Map(func(r rune) rune {
		if r == '\r' || r == '\n' {
			return -1
		}
		return r
	}, subject)
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedHeaderSubject)
	// Encode subject using RFC 2047 quoted-printable to handle non-ASCII characters
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Escape user inputs to prevent injection issues
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct plain text body
	plainBody := fmt.Sprintf(`User Feedback Received

Submitted by: %s
Subject: %s
Message:
%s`, escapedUserName, escapedSubject, escapedFeedbackContent)

	// Construct HTML body with escaped user input to prevent HTML injection
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// Generate a boundary for multipart message
	boundary := "----=_NextPart_000_0001_01D4C3F1.23456789"

	// Encode plain text body using quoted-printable
	var qpPlainBuffer bytes.Buffer
	qpPlainWriter := quotedprintable.NewWriter(&qpPlainBuffer)
	if _, err := qpPlainWriter.Write([]byte(plainBody)); err != nil {
		return "", fmt.Errorf("failed to encode plain body: %w", err)
	}
	if err := qpPlainWriter.Close(); err != nil {
		return "", fmt.Errorf("failed to finalize plain body encoding: %w", err)
	}
	encodedPlainBody := qpPlainBuffer.String()

	// Encode HTML body using quoted-printable
	var qpHTMLBuffer bytes.Buffer
	qpHTMLWriter := quotedprintable.NewWriter(&qpHTMLBuffer)
	if _, err := qpHTMLWriter.Write([]byte(htmlBody)); err != nil {
		return "", fmt.Errorf("failed to encode html body: %w", err)
	}
	if err := qpHTMLWriter.Close(); err != nil {
		return "", fmt.Errorf("failed to finalize html body encoding: %w", err)
	}
	encodedHTMLBody := qpHTMLBuffer.String()

	// Construct email headers
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: multipart/alternative; boundary=%s\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
		boundary,
	)

	// Construct multipart body
	multipartBody := fmt.Sprintf("--%s\r\nContent-Type: text/plain; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n%s\r\n--%s\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n%s\r\n--%s--",
		boundary,
		encodedPlainBody,
		boundary,
		encodedHTMLBody,
		boundary,
	)

	// Combine headers and multipart body
	emailMessage := headers + multipartBody

	return emailMessage, nil
}

