package main

import (
	"errors"
	"fmt"
	"html"
	"mime"
	"strings"
)

// BuildFeedbackEmail constructs a complete HTML email for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate required inputs
	if fromAddr == "" {
		return "", errors.New("from address is required")
	}
	if toAddr == "" {
		return "", errors.New("to address is required")
	}
	if userName == "" {
		return "", errors.New("user name is required")
	}
	if subject == "" {
		return "", errors.New("feedback subject is required")
	}
	if feedbackContent == "" {
		return "", errors.New("feedback content is required")
	}

	// Encode email subject to handle non-ASCII characters
	encodedSubject := mime.QEncoding.Encode("utf-8", subject)

	// Escape user inputs to prevent HTML injection and format feedback
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)
	// Convert newlines to HTML breaks
	formattedFeedback := strings.ReplaceAll(strings.ReplaceAll(escapedFeedback, "\r\n", "<br>"), "\n", "<br>")

	// Construct HTML body with styling
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 800px; margin: 20px auto; padding: 0 20px; }
        .feedback-container { border: 1px solid #e0e0e0; border-radius: 8px; padding: 20px; background-color: #f9f9f9; }
        .feedback-header { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 10px; margin-bottom: 20px; }
        .field { margin-bottom: 18px; }
        .field-label { font-weight: bold; display: block; margin-bottom: 6px; color: #34495e; }
        .field-value { padding: 12px; background-color: #ffffff; border: 1px solid #dcdde1; border-radius: 4px; line-height: 1.5; }
    </style>
</head>
<body>
    <div class="feedback-container">
        <h2 class="feedback-header">New User Feedback Received</h2>
        <div class="field">
            <span class="field-label">Username:</span>
            <div class="field-value">%s</div>
        </div>
        <div class="field">
            <span class="field-label">Feedback Subject:</span>
            <div class="field-value">%s</div>
        </div>
        <div class="field">
            <span class="field-label">Feedback Content:</span>
            <div class="field-value">%s</div>
        </div>
    </div>
</body>
</html>`, escapedUserName, escapedSubject, formattedFeedback)

	// Build complete email with headers and body
	var emailBuf strings.Builder
	emailBuf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	emailBuf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	emailBuf.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	emailBuf.WriteString("MIME-Version: 1.0\r\n")
	emailBuf.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	emailBuf.WriteString("Content-Transfer-Encoding: 8bit\r\n")
	emailBuf.WriteString("\r\n") // Separate headers and body
	emailBuf.WriteString(htmlContent)

	return emailBuf.String(), nil
}

func main() {
	// Example usage
	fromAddr := "user@example.com"
	toAddr := "support@example.com"
	userName := "张三 (John Doe)"
	subject := "Feedback about the new feature 测试"
	feedbackContent := "Hello Support Team,\n\nI've been testing the new feature and have some feedback.\n\n1. It's very responsive, which is great!\n2. I wish there was a dark mode option.\n3. The loading screen could be a bit shorter.\n\nOverall, excellent work!\n\nBest regards,\n张三"

	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Failed to build email: %v\n", err)
		return
	}

	fmt.Println("Generated Feedback Email:")
	fmt.Println("==========================")
	fmt.Println(emailBody)
}

