package main

import (
	"bytes"
	"fmt"
	"html"
	"mime"
	"mime/quotedprintable"
	"net/mail"
	"strings"
	"time"
)

func escapeAllHTML(s string) string {
	s = html.EscapeString(s)
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Parse and validate email addresses
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject to remove CR/LF to prevent header injection
	sanitizedSubject := strings.Map(func(r rune) rune {
		if r == '\r' || r == '\n' {
			return ' '
		}
		return r
	}, subject)
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)
	// Encode subject for proper MIME header handling (supports non-ASCII)
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

	// Generate HTML body with escaped user input to prevent XSS
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapeAllHTML(userName),
		escapeAllHTML(subject),
		escapeAllHTML(feedbackContent),
	)

	// Encode HTML body using quoted-printable for safe transport
	var buf bytes.Buffer
	qpWriter := quotedprintable.NewWriter(&buf)
	if _, err := qpWriter.Write([]byte(htmlBody)); err != nil {
		return "", fmt.Errorf("failed to encode body: %w", err)
	}
	if err := qpWriter.Close(); err != nil {
		return "", fmt.Errorf("failed to finalize body encoding: %w", err)
	}
	encodedBody := buf.String()

	// Construct email headers with proper RFC 5322 formatting
	date := time.Now().Format(time.RFC1123Z)
	headers := fmt.Sprintf(
		"Date: %s\r\n"+
			"From: %s\r\n"+
			"To: %s\r\n"+
			"Subject: %s\r\n"+
			"MIME-Version: 1.0\r\n"+
			"Content-Type: text/html; charset=UTF-8\r\n"+
			"Content-Transfer-Encoding: quoted-printable\r\n"+
			"\r\n",
		date,
		from.String(),
		to.String(),
		encodedSubject,
	)

	// Combine headers and encoded body
	emailMessage := headers + encodedBody

	return emailMessage, nil
}

