            <span class="label">Feedback Content:</span>
            <div class="feedback-content">{{.FeedbackContent}}</div>
        </div>
    </div>
</body>
</html>
`

type emailData struct {
	UserName        string
	Subject         string
	FeedbackContent string
}

// BuildFeedbackEmail constructs an HTML email for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Parse the HTML template
	tmpl, parseErr := template.New("feedbackEmail").Parse(emailTemplate)
	if parseErr != nil {
		return "", fmt.Errorf("failed to parse email template: %w", parseErr)
	}

	// Prepare data for template execution
	data := emailData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute template to generate HTML body
	var htmlBody bytes.Buffer
	if execErr := tmpl.Execute(&htmlBody, data); execErr != nil {
		return "", fmt.Errorf("failed to execute email template: %w", execErr)
	}

	// Construct email headers with proper CRLF line endings
	emailSubject := fmt.Sprintf("User Feedback from %s: %s", userName, subject)
	headers := fmt.Sprintf(
		"From: %s\r\n"+
			"To: %s\r\n"+
			"Subject: %s\r\n"+
			"MIME-Version: 1.0\r\n"+
			"Content-Type: text/html; charset=\"UTF-8\"\r\n"+
			"\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Combine headers and HTML body into final email content
	emailBody = headers + htmlBody.String()

	return emailBody, nil
}

func main() {
	// Example usage
