// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format and parse into mail.Address structs
	fromAddress, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toAddress, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Format From header with encoded display name if present
	var fromHeader string
	if fromAddress.Name != "" {
		encodedFromName := mime.QEncoding.Encode("utf-8", fromAddress.Name)
		fromHeader = fmt.Sprintf("%s <%s>", encodedFromName, fromAddress.Address)
	} else {
		fromHeader = fromAddress.Address
	}

	// Format To header with encoded display name if present
	var toHeader string
	if toAddress.Name != "" {
		encodedToName := mime.QEncoding.Encode("utf-8", toAddress.Name)
		toHeader = fmt.Sprintf("%s <%s>", encodedToName, toAddress.Address)
	} else {
		toHeader = toAddress.Address
	}

	// Construct and encode email subject for RFC compliance
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

	// Construct email headers with proper MIME configuration
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromHeader,
		toHeader,
		encodedSubject,
	)

	// Construct HTML body with escaped user input to prevent HTML injection
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		template.HTMLEscapeString(userName),
		template.HTMLEscapeString(subject),
		template.HTMLEscapeString(feedbackContent),
	)

	// Combine headers and body into final email message
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

