            font-weight: bold;
            color: #555555;
            display: block;
            margin-bottom: 5px;
        }
        .field-value {
            color: #333333;
            padding-left: 10px;
        }
        .content-box {
            background-color: #f9f9f9;
            padding: 15px;
            border-radius: 4px;
            border-left: 4px solid #4a90e2;
            white-space: pre-wrap;
            word-wrap: break-word;
        }
    </style>
</head>
<body>
    <div class="email-container">
        <div class="header">
            <h1>New User Feedback Submission</h1>
        </div>
        <div class="feedback-section">
            <div class="field">
                <span class="field-label">Username:</span>
                <span class="field-value">{{.UserName}}</span>
            </div>
            <div class="field">
                <span class="field-label">Feedback Subject:</span>
                <span class="field-value">{{.Subject}}</span>
            </div>
            <div class="field">
                <span class="field-label">Feedback Content:</span>
                <div class="content-box">{{.FeedbackContent}}</div>
            </div>
        </div>
    </div>
</body>
</html>
`

type emailData struct {
	UserName        string
	Subject         string
	FeedbackContent string
}

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate input parameters
	if fromAddr == "" {
		return "", errors.New("from address cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("to address cannot be empty")
	}
	if userName == "" {
		return "", errors.New("user name cannot be empty")
	}
	if subject == "" {
		return "", errors.New("feedback subject cannot be empty")
	}

	// Parse HTML template
	tmpl, err := template.New("feedbackEmail").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare template data
	data := emailData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute template to generate HTML body
	var htmlBody bytes.Buffer
	if err := tmpl.Execute(&htmlBody, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Encode email subject for proper UTF-8 handling
	emailSubject := fmt.Sprintf("New User Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

	// Build email headers
	var headers bytes.Buffer
	headers.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	headers.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	headers.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	headers.WriteString("MIME-Version: 1.0\r\n")
	headers.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	headers.WriteString("Content-Transfer-Encoding: 8bit\r\n")
	headers.WriteString("\r\n") // Separate headers from body

	// Combine headers and HTML body
	var fullEmail bytes.Buffer
	fullEmail.Write(headers.Bytes())
	fullEmail.Write(htmlBody.Bytes())

	return fullEmail.String(), nil
}

func main() {
	// Example usage
	from := "user@example.com"
	to := "support@example.com"
	userName := "john_doe"
	subject := "Login Issue"
	feedback := "Hi, I'm having trouble logging into my account. When I enter my credentials, the page just reloads without any error message. Can you please help?\n\nThanks!"

	email, err := BuildFeedbackEmail(from, to, userName, subject, feedback)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email:")
	fmt.Println(email)
}

