// BuildFeedbackEmail constructs a MIME-compliant HTML email for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate required inputs
	if fromAddr == "" {
		return "", fmt.Errorf("from address cannot be empty")
	}
	if toAddr == "" {
		return "", fmt.Errorf("to address cannot be empty")
	}
	if userName == "" {
		return "", fmt.Errorf("user name cannot be empty")
	}
	if subject == "" {
		return "", fmt.Errorf("feedback subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedback content cannot be empty")
	}

	// Encode email subject to handle non-ASCII characters per RFC 2047
	encodedSubject := mime.QEncoding.Encode("utf-8", subject)

	// Escape user inputs to prevent HTML injection
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Build HTML email body with styling
	htmlBody := fmt.Sprintf(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>User Feedback</title>
    <style>
        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
            max-width: 800px;
            margin: 20px auto;
            padding: 0 20px;
            color: #333;
            line-height: 1.6;
        }
        .header {
            background: linear-gradient(135deg, #667eea 0%%, #764ba2 100%%);
            color: white;
            padding: 25px;
            border-radius: 12px;
            margin-bottom: 30px;
        }
        .header h1 {
            margin: 0;
            font-size: 24px;
            font-weight: 600;
        }
        .field-group {
            margin-bottom: 25px;
        }
        .field-label {
            font-weight: 600;
            font-size: 14px;
            text-transform: uppercase;
            color: #666;
            margin-bottom: 8px;
            letter-spacing: 0.5px;
        }
        .field-value {
            background-color: #f8f9fa;
            padding: 15px;
            border-radius: 8px;
            border: 1px solid #e9ecef;
            font-size: 16px;
        }
        .content-value {
            white-space: pre-wrap;
            word-wrap: break-word;
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>📬 New User Feedback Received</h1>
    </div>

    <div class="field-group">
        <div class="field-label">User Name</div>
        <div class="field-value">%s</div>
    </div>

    <div class="field-group">
        <div class="field-label">Feedback Subject</div>
        <div class="field-value">%s</div>
    </div>

    <div class="field-group">
