`, escapedUserName, escapedSubject, escapedContent)

	// Construct email headers per RFC 5322 (using CRLF line endings)
	headers := []string{
		fmt.Sprintf("From: %s", fromAddr),
		fmt.Sprintf("To: %s", toAddr),
		fmt.Sprintf("Subject: %s", encodedSubject),
		"MIME-Version: 1.0",
		"Content-Type: text/html; charset=\"UTF-8\"",
	}

	// Combine headers and body with proper separation
	emailBody = strings.Join(headers, "\r\n") + "\r\n\r\n" + htmlBody

	return emailBody, nil
}

func main() {
	// Example usage of BuildFeedbackEmail
	from := "feedback-user@example.com"
	to := "customer-support@example.com"
	userName := "李明 (Li Ming)"
	subject := "Suggestion for improving the checkout process — 优化结账流程的建议"
	feedbackContent := `Hello team,

I have been using your service for a few months and I love it! However, I noticed that the checkout process can be a bit confusing for first-time users.

Suggestions:
1. Add a progress indicator to show how many steps are left
2. Allow guests to checkout without creating an account
3. Improve error messages for payment failures

Thanks for your hard work!
谢谢！

Best regards,
李明`

	// Generate the email
	email, err := BuildFeedbackEmail(from, to, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Failed to build feedback email: %v\n", err)
		return
	}

	// Print the generated email (in real usage, you'd pass this to smtp.SendMail)
	fmt.Println("=== Generated Feedback Email ===")
	fmt.Println(email)
}

