	toAddress, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Format From header with encoded display name if needed
	var fromHeader string
	if fromAddress.Name != "" {
		encodedName := mime.QEncoding.Encode("utf-8", fromAddress.Name)
		fromHeader = fmt.Sprintf("%s <%s>", encodedName, fromAddress.Address)
	} else {
		fromHeader = fromAddress.Address
	}

	// Format To header with encoded display name if needed
	var toHeader string
	if toAddress.Name != "" {
		encodedName := mime.QEncoding.Encode("utf-8", toAddress.Name)
		toHeader = fmt.Sprintf("%s <%s>", encodedName, toAddress.Address)
	} else {
		toHeader = toAddress.Address
	}

	// Construct and encode email subject
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

	// Construct email headers with proper MIME settings
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromHeader,
		toHeader,
		encodedSubject,
	)

	// Construct HTML body with escaped user input to prevent HTML injection
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)

	// Combine headers and body
