	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedbackContent cannot be empty")
	}

	// Parse the HTML template
	t, err := template.New("feedbackEmail").Parse(htmlTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare data structure for template execution
	templateData := struct {
		UserName        string
		FeedbackSubject string
		FeedbackContent string
	}{
		UserName:        userName,
		FeedbackSubject: subject,
		FeedbackContent: feedbackContent,
	}

	// Execute template to generate HTML body
	var htmlBodyBuffer bytes.Buffer
	if err := t.Execute(&htmlBodyBuffer, templateData); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Encode email subject with MIME Q-encoding to support non-ASCII characters
	emailSubject := fmt.Sprintf("New User Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

