	headersBuffer.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	headersBuffer.WriteString("\r\n") // Blank line separates headers from body

	// Combine headers and HTML body into full email message
	var fullEmailBuffer bytes.Buffer
	fullEmailBuffer.Write(headersBuffer.Bytes())
	fullEmailBuffer.Write(htmlBodyBuffer.Bytes())

	return fullEmailBuffer.String(), nil
}

