		return r
	}, subject)

	// Construct and encode email subject
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Construct email headers with properly formatted addresses and encoded subject
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddrParsed.String(),
		toAddrParsed.String(),
		encodedSubject,
	)

	// Escape user inputs to prevent HTML injection
