// BuildFeedbackEmail constructs a standards-compliant HTML email for user feedback
// compatible with net/smtp.SendMail
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate required input parameters
	if fromAddr == "" {
		return "", errors.New("from address cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("to address cannot be empty")
	}
	if userName == "" {
		return "", errors.New("user name cannot be empty")
	}
	if subject == "" {
		return "", errors.New("feedback subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", errors.New("feedback content cannot be empty")
	}

	// Parse and validate the HTML template
	tmpl, err := template.New("feedbackEmail").Parse(htmlTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare dynamic data for template execution
	data := emailData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Render the template into a buffer to get the HTML body
	var bodyBuffer bytes.Buffer
	if err = tmpl.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to render email template: %w", err)
	}

	// Build email headers according to RFC 5322 standards
	var headers []string
	headers = append(headers, fmt.Sprintf("From: %s", fromAddr))
	headers = append(headers, fmt.Sprintf("To: %s", toAddr))
	// Encode subject to support non-ASCII characters
	encodedSubject := mime.QEncoding.Encode("utf-8", subject)
	headers = append(headers, fmt.Sprintf("Subject: %s", encodedSubject))
	headers = append(headers, "MIME-Version: 1.0")
	headers = append(headers, "Content-Type: text/html; charset=\"UTF-8\"")

	// Combine headers and body with proper CRLF line endings
	headerSection := strings.Join(headers, "\r\n")
	fullEmail := fmt.Sprintf("%s\r\n\r\n%s", headerSection, bodyBuffer.String())

	return fullEmail, nil
}

func main() {
	// Example usage of BuildFeedbackEmail
	fromAddress := "feedback-system@example.com"
	toAddress := "customer-support@example.com"
	userName := "Alice Smith"
	feedbackSubject := "Suggestion for improved dashboard filtering"
	feedbackContent := `Hi Support Team,

I love using your product! I have a suggestion to make the dashboard even better:

1. Add date range filtering for the activity log
2. Allow saving custom filter presets
3. Add a dark mode option for the dashboard

These changes would save me a lot of time during my daily workflow.

Thanks for considering!
Alice`

	// Generate the email
	email, err := BuildFeedbackEmail(fromAddress, toAddress, userName, feedbackSubject, feedbackContent)
	if err != nil {
		fmt.Printf("Failed to build feedback email: %v\n", err)
		return
	}

	// Print the generated email (in production, this would be passed to smtp.SendMail)
	fmt.Println("=== Generated Feedback Email ===")
	fmt.Println(email)
}

