	escapedContent := html.EscapeString(feedbackContent)

	var buf bytes.Buffer

	// Write standard email headers with CRLF line endings (per RFC 5322)
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	// Encode subject to handle non-ASCII characters per RFC 2047
	encodedSubject := mime.QEncoding.Encode("utf-8", subject)
