// BuildFeedbackEmail constructs a MIME-compliant HTML email for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate required input parameters
	if fromAddr == "" {
		return "", errors.New("from address cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("to address cannot be empty")
	}
	if userName == "" {
		return "", errors.New("user name cannot be empty")
	}
	if subject == "" {
		return "", errors.New("feedback subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", errors.New("feedback content cannot be empty")
	}

	// Encode email subject to handle non-ASCII characters (per RFC 2047)
	encodedSubject := mime.QEncoding.Encode("utf-8", subject)

	// Create buffer to build email content
	var buf bytes.Buffer

	// Write standard email headers (use CRLF line endings as per RFC 5322)
	fmt.Fprintf(&buf, "From: %s\r\n", fromAddr)
	fmt.Fprintf(&buf, "To: %s\r\n", toAddr)
	fmt.Fprintf(&buf, "Subject: %s\r\n", encodedSubject)
	fmt.Fprintf(&buf, "MIME-Version: 1.0\r\n")
	fmt.Fprintf(&buf, "Content-Type: text/html; charset=\"UTF-8\"\r\n")
